targets.expr:
topk(20,
  sum by (job_title) (max_over_time(claude_code_cost_usage_USD_total[$__range]) * on(user_email) group_left(job_title) topk by (user_email) (1, max by (user_email, job_title) (max_over_time(user_info{rollup_name=~"$rollup_name", manager_name=~"$manager_name", user_email=~"$user_email", job_title!=""}[$__range]))))
)

topk(20,
  avg by (rollup_name) (sum by (user_email, rollup_name) (max_over_time(claude_code_cost_usage_USD_total[$__range]) * on(user_email) group_left(rollup_name) topk by (user_email) (1, max by (user_email, rollup_name) (max_over_time(user_info{rollup_name=~"$rollup_name", manager_name=~"$manager_name", user_email=~"$user_email"}[$__range])))))
)

topk(20,
  avg by (rollup_name) (
    sum by (session_id, rollup_name) (
      max_over_time(claude_code_cost_usage_USD_total[$__range])
      * on(user_email) group_left(rollup_name)
      topk by (user_email) (1, max by (user_email, rollup_name) (
        max_over_time(user_info{rollup_name=~"$rollup_name", manager_name=~"$manager_name", user_email=~"$user_email"}[$__range])
      ))
    )
  )
)

topk(20,
  (count by (rollup_name) (
    (sum by (session_id, rollup_name) (
      max_over_time(claude_code_token_usage_tokens_total{type=~"cacheRead|cacheCreation"}[$__range])
      * on(user_email) group_left(rollup_name)
      topk by (user_email) (1, max by (user_email, rollup_name) (
        max_over_time(user_info{rollup_name=~"$rollup_name", manager_name=~"$manager_name", user_email=~"$user_email"}[$__range])
      ))
    ))
    >= 500000
  ))
  /
  (count by (rollup_name) (
    sum by (session_id, rollup_name) (
      max_over_time(claude_code_token_usage_tokens_total{type=~"cacheRead|cacheCreation"}[$__range])
      * on(user_email) group_left(rollup_name)
      topk by (user_email) (1, max by (user_email, rollup_name) (
        max_over_time(user_info{rollup_name=~"$rollup_name", manager_name=~"$manager_name", user_email=~"$user_email"}[$__range])
      ))
    )
  ))
)

topk(20,
  histogram_quantile(0.5,
    sum by (le, rollup_name) (
      jira_issue_resolution_time_hours_bucket
      * on(user_email) group_left(rollup_name)
      topk by (user_email) (1, max by (user_email, rollup_name) (
        max_over_time(user_info{rollup_name=~"$rollup_name", manager_name=~"$manager_name", user_email=~"$user_email"}[$__range])
      ))
    )
  )
)

topk(10,
  histogram_quantile(0.5,
    sum by (le, priority) (
      jira_issue_resolution_time_hours_bucket
    )
  )
)
